PREFIX mds: <https://cwrusdle.bitbucket.io/mds/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?neighbor ?neighborLabel WHERE {
  ?geohash a mds:Geohash .
  ?geohash rdfs:label "bccc" .
  {
    { ?geohash mds:hasNorthNeighbor ?neighbor }
    UNION { ?geohash mds:hasSouthNeighbor ?neighbor }
    UNION { ?geohash mds:hasEastNeighbor ?neighbor }
    UNION { ?geohash mds:hasWestNeighbor ?neighbor }
    UNION { ?geohash mds:hasNortheastNeighbor ?neighbor }
    UNION { ?geohash mds:hasNorthwestNeighbor ?neighbor }
    UNION { ?geohash mds:hasSoutheastNeighbor ?neighbor }
    UNION { ?geohash mds:hasSouthwestNeighbor ?neighbor }
  }
  ?neighbor rdfs:label ?neighborLabel .
}

PREFIX mds: <https://cwrusdle.bitbucket.io/mds/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?raster ?neighborLabel WHERE {
  ?center a mds:Geohash .
  ?center rdfs:label "dpnq" .
  {
    { ?center mds:hasNorthNeighbor ?neighbor }
    UNION { ?center mds:hasSouthNeighbor ?neighbor }
    UNION { ?center mds:hasEastNeighbor ?neighbor }
    UNION { ?center mds:hasWestNeighbor ?neighbor }
    UNION { ?center mds:hasNortheastNeighbor ?neighbor }
    UNION { ?center mds:hasNorthwestNeighbor ?neighbor }
    UNION { ?center mds:hasSoutheastNeighbor ?neighbor }
    UNION { ?center mds:hasSouthwestNeighbor ?neighbor }
    UNION { BIND(?center AS ?neighbor) }
  }
  ?raster a mds:GeospatialRaster .
  ?raster mds:occupiesSpatialRegion ?neighbor .
  ?neighbor rdfs:label ?neighborLabel .
}

PREFIX mds: <https://cwrusdle.bitbucket.io/mds/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?name ?type WHERE {
  ?agency a mds:Agency .
  ?agency rdfs:label "NASA" .
  {
    ?satellite a mds:Satellite .
    ?satellite mds:ownedByAgency ?agency .
    ?satellite mds:hasSatelliteCommonName ?name .
    BIND("Satellite" AS ?type)
  } UNION {
    ?sensor a mds:Sensor .
    ?sensor mds:ownedByAgency ?agency .
    ?sensor mds:hasSensorCommonName ?name .
    BIND("Sensor" AS ?type)
  }
}
